class PdfPath (  PdfFillElement) :
    """
    Implements graphics path, which is a sequence of primitive graphics elements.
    """
    @dispatch
    def __init__(self):
        GetDllLibPdf().spr_pdf_PdfPath_CreatePdfPath.restype = c_void_p
        intPtr = CallCFunction(GetDllLibPdf().spr_pdf_PdfPath_CreatePdfPath)
        super(PdfPath, self).__init__(intPtr)

    @dispatch
    def __init__(self, pen:PdfPen):
        ptrPen:c_void_p = pen.Ptr
        GetDllLibPdf().spr_pdf_PdfPath_CreatePdfPathP.argtypes=[c_void_p]
        GetDllLibPdf().spr_pdf_PdfPath_CreatePdfPathP.restype = c_void_p
        intPtr = CallCFunction(GetDllLibPdf().spr_pdf_PdfPath_CreatePdfPathP,ptrPen)
        super(PdfPath, self).__init__(intPtr)

    @dispatch
    def __init__(self, brush:PdfBrush):
        ptrBrush:c_void_p = brush.Ptr
        GetDllLibPdf().spr_pdf_PdfPath_CreatePdfPathB.argtypes=[c_void_p]
        GetDllLibPdf().spr_pdf_PdfPath_CreatePdfPathB.restype = c_void_p
        intPtr = CallCFunction(GetDllLibPdf().spr_pdf_PdfPath_CreatePdfPathB,ptrBrush)
        super(PdfPath, self).__init__(intPtr)

    @dispatch
    def __init__(self, brush:PdfBrush,fillMode:PdfFillMode ):
        ptrBrush:c_void_p = brush.Ptr
        enumMode:c_int = fillMode.value

        GetDllLibPdf().spr_pdf_PdfPath_CreatePdfPathBF.argtypes=[c_void_p,c_int]
        GetDllLibPdf().spr_pdf_PdfPath_CreatePdfPathBF.restype = c_void_p
        intPtr = CallCFunction(GetDllLibPdf().spr_pdf_PdfPath_CreatePdfPathBF,ptrBrush,enumMode)
        super(PdfPath, self).__init__(intPtr)

    @dispatch
    def __init__(self,  pen:PdfPen,brush:PdfBrush,fillMode:PdfFillMode ):
        ptrPen:c_void_p = pen.Ptr
        ptrBrush:c_void_p = brush.Ptr
        enumMode:c_int = fillMode.value

        GetDllLibPdf().spr_pdf_PdfPath_CreatePdfPathPBF.argtypes=[c_void_p,c_void_p,c_int]
        GetDllLibPdf().spr_pdf_PdfPath_CreatePdfPathPBF.restype = c_void_p
        intPtr = CallCFunction(GetDllLibPdf().spr_pdf_PdfPath_CreatePdfPathPBF,ptrPen,ptrBrush,enumMode)
        super(PdfPath, self).__init__(intPtr)

    @property

    def FillMode(self)->'PdfFillMode':
        """
        Gets or sets the fill mode.
        """
        GetDllLibPdf().spr_pdf_PdfPath_get_FillMode.argtypes=[c_void_p]
        GetDllLibPdf().spr_pdf_PdfPath_get_FillMode.restype=c_int
        ret = CallCFunction(GetDllLibPdf().spr_pdf_PdfPath_get_FillMode,self.Ptr)
        objwraped = PdfFillMode(ret)
        return objwraped

    @FillMode.setter
    def FillMode(self, value:'PdfFillMode'):
        GetDllLibPdf().spr_pdf_PdfPath_set_FillMode.argtypes=[c_void_p, c_int]
        CallCFunction(GetDllLibPdf().spr_pdf_PdfPath_set_FillMode,self.Ptr, value.value)

